#include <stdio.h>
#include <stdlib.h>

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N,M; scanf("%d %d", &N, &M);
        long long *B = (long long*)malloc(N*sizeof(long long));
        long long *Z = (long long*)malloc(M*sizeof(long long));
        for(int i=0;i<N;i++) scanf("%lld", &B[i]);
        for(int i=0;i<M;i++) scanf("%lld", &Z[i]);
        if(N==1){
            printf("YES\n");
            free(B); free(Z);
            continue;
        }
        int ok=1;
        for(int i=1;i<N;i++) if(B[i] < B[i-1]){ ok=0; break; }
        if(!ok){ printf("NO\n"); free(B); free(Z); continue; }
        int idx=0; // position in Z
        for(int i=1;i<N && ok;i++){
            long long delta = B[i] - B[i-1];
            if(delta==0) continue; // empty group
            long long cur=0;
            while(idx<M && cur<delta){ cur += Z[idx]; idx++; }
            if(cur!=delta) ok=0; // either ran out or exceeded
        }
        printf(ok?"YES\n":"NO\n");
        free(B); free(Z);
    }
    return 0;
}

