import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            int N = fs.nextInt();
            int M = fs.nextInt();
            long[] B = new long[N];
            long[] Z = new long[M];
            for (int i = 0; i < N; i++) B[i] = fs.nextLong();
            for (int i = 0; i < M; i++) Z[i] = fs.nextLong();
            if (N == 1) { sb.append("YES\n"); continue; }
            boolean ok = true;
            for (int i = 1; i < N; i++) if (B[i] < B[i-1]) { ok = false; break; }
            if (!ok) { sb.append("NO\n"); continue; }
            int idx = 0;
            for (int i = 1; i < N && ok; i++) {
                long delta = B[i] - B[i-1];
                if (delta == 0) continue;
                long cur = 0;
                while (idx < M && cur < delta) { cur += Z[idx]; idx++; }
                if (cur != delta) ok = false;
            }
            sb.append(ok ? "YES" : "NO").append('\n');
        }
        System.out.print(sb.toString());
    }

    // Fast scanner for large input
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in) { this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        long nextLong() throws IOException { return Long.parseLong(next()); }
        int nextInt() throws IOException { return Integer.parseInt(next()); }
        String next() throws IOException {
            StringBuilder sb = new StringBuilder();
            int c;
            while ((c = readByte()) != -1 && c <= ' ') ; // skip whitespace
            if (c == -1) return null;
            do { sb.append((char)c); } while ((c = readByte()) != -1 && c > ' ');
            return sb.toString();
        }
    }
}

