import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it)); M = int(next(it))
        B = [int(next(it)) for _ in range(N)]
        Z = [int(next(it)) for _ in range(M)]
        if N == 1:
            out.append('YES')
            continue
        ok = True
        for i in range(1, N):
            if B[i] < B[i-1]:
                ok = False
                break
        if not ok:
            out.append('NO')
            continue
        idx = 0
        for i in range(1, N):
            delta = B[i] - B[i-1]
            if delta == 0:
                continue
            cur = 0
            while idx < M and cur < delta:
                cur += Z[idx]
                idx += 1
            if cur != delta:
                ok = False
                break
        out.append('YES' if ok else 'NO')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

